namespace sv_d6cfb435277f4f24b4e781e2c02d6155.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service holding the currently selected warehouse for this circuit.
/// Components subscribe to <see cref="OnChange"/> to re-render when the
/// selection changes. Scoped lifetime ensures each user circuit has its own
/// independent warehouse selection.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_d6cfb435277f4f24b4e781e2c02d6155.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Each circuit (user session) gets its own instance so polling and alert counts
/// are independent per user.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }

    /// <summary>
    /// Fired from the polling background task whenever new data arrives.
    /// Subscribers MUST wrap StateHasChanged in InvokeAsync because this
    /// event fires outside the Blazor synchronization context.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query returning a random low-stock count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts 10-second polling if not already running. Multiple components can
    /// call this; polling starts on first subscriber and stops when all unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_timer is not null) return;

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount > 0) return;

        _cts?.Cancel();
        _timer?.Dispose();
        _timer = null;
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire an initial poll immediately so data is available right away.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct)) break;
                await RefreshAsync();
            }
            catch (OperationCanceledException) { break; }
        }
    }

    private async Task RefreshAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

