@using sv_d6cfb435277f4f24b4e781e2c02d6155.Services
@inject WarehouseState WarehouseState
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" style="width: auto;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
    }

    private void OnStateChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => WarehouseState.OnChange -= OnStateChanged;
}

@using sv_d6cfb435277f4f24b4e781e2c02d6155.Services
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-2">@AlertService.CurrentAlertCount</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

