<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
                <small class="text-muted">@WarehouseState.CurrentWarehouseId</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card @(AlertService.CurrentAlertCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="display-6 @(AlertService.CurrentAlertCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.CurrentAlertCount
                </p>
                <small class="text-muted">Items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">🟢</p>
                <small class="text-muted">Refreshing every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        _alertHandler = () => InvokeAsync(StateHasChanged);
        _warehouseHandler = () => InvokeAsync(StateHasChanged);

        AlertService.OnAlertCountChanged += _alertHandler;
        WarehouseState.OnChange += _warehouseHandler;

        // Start polling when the dashboard becomes visible.
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        WarehouseState.OnChange -= _warehouseHandler;

        // Stop polling when the user leaves the dashboard.
        AlertService.StopPolling();
    }
}
